<script>
import { ref, computed, onMounted, watch } from 'vue';
import MapView from './components/MapView.vue';

export default {
  name: 'App',
  components: {
    MapView
  },
  setup() {
    // State
    const isSidebarCollapsed = ref(false);
    const activeView = ref('map');
    const isDarkMode = ref(false);
    const isPlaying = ref(false);
    const isProcessing = ref(false);
    const systemStatus = ref('idle');
    const lastUpdate = ref('Never');
    const hasNotifications = ref(false);
    const selectedMetric = ref('iwr');
    const selectedTimeframe = ref('30d');
    const selectedDate = ref('');
    
    const availableDates = ref([]);
    const currentDateIndex = ref(0);
    const layers = ref([
      { id: 'savi', name: 'SAVI', visible: true, unit: 'index', color: '#10B981' },
      { id: 'kc', name: 'Crop Coefficient', visible: true, unit: 'ratio', color: '#3B82F6' },
      { id: 'cwr', name: 'Crop Water Requirement', visible: true, unit: 'mm/day', color: '#F59E0B' },
      { id: 'iwr', name: 'Irrigation Water Requirement', visible: true, unit: 'mm/day', color: '#EF4444' }
    ]);
    
    const mapView = ref(null);
    
    // Navigation items
    const navItems = [
      { id: 'map', name: 'Map View', icon: 'fas fa-map-marked-alt' },
      { id: 'analytics', name: 'Analytics', icon: 'fas fa-chart-bar' },
      { id: 'forecast', name: 'Forecast', icon: 'fas fa-chart-line' },
      { id: 'data', name: 'Data Management', icon: 'fas fa-database' },
      { id: 'reports', name: 'Reports', icon: 'fas fa-file-alt' }
    ];
    
    // Computed
    const currentPage = computed(() => {
      const page = navItems.find(item => item.id === activeView.value);
      return {
        title: page ? page.name : 'Dashboard',
        subtitle: activeView.value === 'map' ? 'Udham Singh Nagar District' : 'Irrigation Monitoring System'
      };
    });
    
    const formattedCurrentDate = computed(() => {
      if (selectedDate.value) {
        const date = new Date(selectedDate.value);
        return date.toLocaleDateString('en-IN', {
          weekday: 'short',
          year: 'numeric',
          month: 'short',
          day: 'numeric'
        });
      }
      return 'Select Date';
    });
    
    const activeLayersCount = computed(() => {
      return layers.value.filter(layer => layer.visible).length;
    });
    
    const systemStatusText = computed(() => {
      const statusMap = {
        'idle': 'System Ready',
        'loading': 'Loading Data...',
        'processing': 'Processing',
        'error': 'Error Detected'
      };
      return statusMap[systemStatus.value] || systemStatus.value;
    });
    
    const analyticsData = computed(() => {
      // These would come from API in production
      return {
        averageIWR: 85.5,
        averageSAVI: 0.623,
        averageKc: 0.75,
        totalWater: 1250
      };
    });
    
    const recentDates = computed(() => {
      return availableDates.value.slice(-5);
    });
    
    const currentYear = computed(() => {
      return new Date().getFullYear();
    });
    
    // Methods
    const toggleSidebar = () => {
      isSidebarCollapsed.value = !isSidebarCollapsed.value;
    };
    
    const setActiveView = (view) => {
      activeView.value = view;
    };
    
    const toggleTheme = () => {
      isDarkMode.value = !isDarkMode.value;
      document.body.classList.toggle('dark-theme', isDarkMode.value);
    };
    
    const togglePlay = () => {
      isPlaying.value = !isPlaying.value;
      // Implement playback logic here
    };
    
    const prevDate = () => {
      if (currentDateIndex.value > 0) {
        currentDateIndex.value--;
        selectedDate.value = availableDates.value[currentDateIndex.value];
      }
    };
    
    const nextDate = () => {
      if (currentDateIndex.value < availableDates.value.length - 1) {
        currentDateIndex.value++;
        selectedDate.value = availableDates.value[currentDateIndex.value];
      }
    };
    
    const onDateChange = () => {
      const index = availableDates.value.indexOf(selectedDate.value);
      if (index !== -1) {
        currentDateIndex.value = index;
      }
    };
    
    const refreshData = async () => {
      systemStatus.value = 'loading';
      try {
        // Simulate API call
        await new Promise(resolve => setTimeout(resolve, 1500));
        generateSampleData();
        lastUpdate.value = new Date().toLocaleTimeString();
      } catch (error) {
        console.error('Error refreshing data:', error);
      } finally {
        systemStatus.value = 'idle';
      }
    };
    
    const generateSampleData = () => {
      const dates = [];
      const today = new Date();
      for (let i = 30; i >= 0; i--) {
        const date = new Date(today);
        date.setDate(date.getDate() - i);
        dates.push(date.toISOString().split('T')[0]);
      }
      availableDates.value = dates;
      currentDateIndex.value = dates.length - 1;
      selectedDate.value = dates[dates.length - 1];
    };
    
    const handleDateChange = (date) => {
      console.log('Date changed:', date);
    };
    
    const handlePixelClick = (data) => {
      console.log('Pixel data:', data);
    };
    
    const handleLayerToggle = (layer) => {
      console.log('Layer toggled:', layer);
    };
    
    const exportData = () => {
      alert('Export functionality will be implemented');
    };
    
    const showNotifications = () => {
      alert('Notifications panel will be implemented');
    };
    
    const logout = () => {
      if (confirm('Are you sure you want to logout?')) {
        alert('Logout functionality will be implemented');
      }
    };
    
    const downloadAnalytics = () => {
      alert('Analytics export will be implemented');
    };
    
    const runForecast = () => {
      alert('Forecast generation will be implemented');
    };
    
    const importData = () => {
      alert('Data import will be implemented');
    };
    
    const generateReport = () => {
      alert('Report generation will be implemented');
    };
    
    const viewReport = (type) => {
      alert(`Viewing ${type} report`);
    };
    
    const showAbout = () => {
      alert('About page will be implemented');
    };
    
    const showContact = () => {
      alert('Contact page will be implemented');
    };
    
    const showPrivacy = () => {
      alert('Privacy policy will be implemented');
    };
    
    const formatTableDate = (dateStr) => {
      const date = new Date(dateStr);
      return date.toLocaleDateString('en-IN', {
        day: '2-digit',
        month: 'short',
        year: 'numeric'
      });
    };
    
    const getForecastValue = (day) => {
      // This would come from API in production
      return (80 + Math.sin(day * 0.5) * 10).toFixed(1);
    };
    
    const getRandomValue = (min, max, decimals) => {
      const value = Math.random() * (max - min) + min;
      return value.toFixed(decimals);
    };
    
    // Initialize
    onMounted(() => {
      generateSampleData();
    });
    
    return {
      // State
      isSidebarCollapsed,
      activeView,
      isDarkMode,
      isPlaying,
      isProcessing,
      systemStatus,
      lastUpdate,
      hasNotifications,
      selectedMetric,
      selectedTimeframe,
      selectedDate,
      availableDates,
      currentDateIndex,
      layers,
      mapView,
      
      // Data
      navItems,
      
      // Computed
      currentPage,
      formattedCurrentDate,
      activeLayersCount,
      systemStatusText,
      analyticsData,
      recentDates,
      currentYear,
      
      // Methods
      toggleSidebar,
      setActiveView,
      toggleTheme,
      togglePlay,
      prevDate,
      nextDate,
      onDateChange,
      refreshData,
      handleDateChange,
      handlePixelClick,
      handleLayerToggle,
      exportData,
      showNotifications,
      logout,
      downloadAnalytics,
      runForecast,
      importData,
      generateReport,
      viewReport,
      showAbout,
      showContact,
      showPrivacy,
      formatTableDate,
      getForecastValue,
      getRandomValue
    };
  }
};
</script>

