<template>
  <div class="irrigation-dashboard">
    <!-- Map Container -->
    <div id="map" class="map-container" ref="mapContainer">
      <!-- Popup -->
      <div id="popup" class="ol-popup" ref="popup">
        <div id="popup-content" ref="popupContent"></div>
        <div id="popup-closer" class="ol-popup-closer" @click="closePopup">
          <i class="fas fa-times"></i>
        </div>
      </div>
    </div>

    <!-- Floating Controls Container -->
    <div class="floating-controls">
      <!-- Time Controls -->
      <div class="time-controls" v-if="availableDates.length > 0">
        <div class="time-slider-container">
          <button @click="togglePlay" class="play-button" :class="{ playing: isPlaying }">
            <i :class="isPlaying ? 'fas fa-pause' : 'fas fa-play'"></i>
          </button>
          
          <div class="slider-wrapper">
            <input 
              type="range" 
              v-model="currentDateIndex" 
              :min="0" 
              :max="availableDates.length - 1" 
              step="1"
              class="date-slider"
              @input="updateMapDate"
            />
            <div class="slider-ticks">
              <span v-for="(date, index) in tickDates" :key="index" 
                    :style="{ left: `${(index / (tickDates.length - 1)) * 100}%` }">
                {{ formatTickDate(date) }}
              </span>
            </div>
          </div>
          
          <div class="date-display">
            <span class="current-date">{{ formattedCurrentDate }}</span>
            <span class="date-info">{{ currentDateIndex + 1 }} of {{ availableDates.length }}</span>
          </div>
        </div>
      </div>

      <!-- Layer Controls Panel -->
      <div class="layer-controls-panel">
        <div class="panel-header" @click="toggleLayerPanel">
          <h3><i class="fas fa-layer-group"></i> Map Layers</h3>
          <i class="fas fa-chevron-down" :class="{ rotated: !isLayerPanelOpen }"></i>
        </div>
        
        <div class="panel-content" v-if="isLayerPanelOpen">
          <!-- Base Map Selection -->
          <div class="control-group">
            <label>Base Map:</label>
            <select v-model="selectedBaseMap" @change="changeBaseMap">
              <option value="satellite">Satellite View</option>
              <option value="osm">Street Map</option>
              <option value="topographic">Topographic</option>
              <option value="terrain">Terrain</option>
            </select>
          </div>
          
          <!-- Layer Toggles -->
          <div class="layer-list">
            <div v-for="layer in layers" :key="layer.id" class="layer-toggle">
              <div class="layer-header">
                <label>
                  <input 
                    type="checkbox" 
                    v-model="layer.visible" 
                    @change="toggleLayer(layer)"
                  >
                  <span class="toggle-label">
                    <i :class="getLayerIcon(layer.id)"></i>
                    {{ layer.name }}
                  </span>
                </label>
                <button @click="toggleLayerOptions(layer.id)" class="options-btn">
                  <i class="fas fa-cog"></i>
                </button>
              </div>
              
              <div v-if="layer.visible && expandedLayers[layer.id]" class="layer-options">
                <!-- Layer Opacity -->
                <div class="layer-opacity">
                  <label>Opacity:</label>
                  <input 
                    type="range" 
                    v-model="layer.opacity" 
                    min="0.1" 
                    max="1" 
                    step="0.1"
                    @input="updateLayerOpacity(layer)"
                  />
                  <span>{{ Math.round((layer.opacity || 0.8) * 100) }}%</span>
                </div>
                
                <!-- Layer Stats -->
                <div v-if="layerStats[layer.id]" class="layer-stats">
                  <div class="stat-row">
                    <span>Min:</span>
                    <span>{{ layerStats[layer.id].min.toFixed(2) }}</span>
                  </div>
                  <div class="stat-row">
                    <span>Max:</span>
                    <span>{{ layerStats[layer.id].max.toFixed(2) }}</span>
                  </div>
                  <div class="stat-row">
                    <span>Avg:</span>
                    <span>{{ layerStats[layer.id].mean.toFixed(2) }} {{ layer.unit }}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
          
          <!-- GEE Boundary Controls -->
          <div class="boundary-controls">
            <div class="control-group">
              <label class="boundary-toggle">
                <input type="checkbox" v-model="showGEEBoundary" @change="toggleGEEBoundary">
                <i class="fas fa-draw-polygon"></i> Show GEE Exact Boundary
              </label>
              <button @click="showBoundaryInfo" class="info-btn">
                <i class="fas fa-info-circle"></i>
              </button>
            </div>
            <div v-if="showGEEBoundary" class="boundary-style">
              <label>Color:</label>
              <input type="color" v-model="boundaryColor" @change="updateBoundaryStyle">
              <label>Opacity:</label>
              <input type="range" v-model="boundaryOpacity" min="0" max="1" step="0.1" 
                     @input="updateBoundaryStyle">
            </div>
          </div>
        </div>
      </div>

      <!-- Map Controls -->
      <div class="map-controls">
        <button @click="zoomIn" class="control-btn" title="Zoom In">
          <i class="fas fa-plus"></i>
        </button>
        <button @click="zoomOut" class="control-btn" title="Zoom Out">
          <i class="fas fa-minus"></i>
        </button>
        <button @click="resetView" class="control-btn" title="Reset View">
          <i class="fas fa-home"></i>
        </button>
        <button @click="toggleFullscreen" class="control-btn" title="Fullscreen">
          <i class="fas fa-expand"></i>
        </button>
      </div>

      <!-- System Status -->
      <div class="system-status" :class="systemStatus">
        <div class="status-indicator">
          <i class="fas fa-circle"></i>
          <span class="status-text">{{ systemStatusText }}</span>
        </div>
        <div class="status-details">
          <span class="detail">Last update: {{ lastUpdate }}</span>
        </div>
      </div>
    </div>

    <!-- Pixel Info Panel -->
    <div class="pixel-info-panel" v-if="pixelInfo">
      <div class="panel-header">
        <h3><i class="fas fa-info-circle"></i> Pixel Information</h3>
        <button @click="clearPixelInfo" class="close-btn">
          <i class="fas fa-times"></i>
        </button>
      </div>
      
      <div class="panel-content">
        <div class="info-section">
          <div class="info-item">
            <span class="label">Location:</span>
            <span class="value">{{ pixelInfo.location.lat.toFixed(4) }}° N, {{ pixelInfo.location.lon.toFixed(4) }}° E</span>
          </div>
          <div class="info-item">
            <span class="label">Date:</span>
            <span class="value">{{ pixelInfo.date }}</span>
          </div>
          <div class="info-item">
            <span class="label">Within GEE Exact Boundary:</span>
            <span class="value" :class="{ 'within': pixelInfo.within_boundary, 'outside': !pixelInfo.within_boundary }">
              {{ pixelInfo.within_boundary ? 'Yes' : 'No' }}
            </span>
          </div>
        </div>
        
        <div class="info-section" v-if="pixelInfo.values && !pixelInfo.values.error">
          <div class="parameter-grid">
            <div v-for="(value, param) in pixelInfo.values" :key="param" class="parameter-card">
              <div class="param-header">
                <i :class="getLayerIcon(param)"></i>
                <h4>{{ getParameterName(param) }}</h4>
              </div>
              <div class="param-value">
                {{ typeof value === 'number' ? value.toFixed(3) : value }}
                <span class="unit">{{ getParameterUnit(param) }}</span>
              </div>
              <div v-if="layerStats[param]" class="param-stats">
                <div>Min: {{ layerStats[param].min.toFixed(2) }}</div>
                <div>Avg: {{ layerStats[param].mean.toFixed(2) }}</div>
                <div>Max: {{ layerStats[param].max.toFixed(2) }}</div>
              </div>
            </div>
          </div>
        </div>
      </div>
      
      <div class="panel-actions">
        <button @click="downloadPixelData" class="action-btn">
          <i class="fas fa-download"></i> Export
        </button>
        <button @click="addToFavorites" class="action-btn">
          <i class="fas fa-star"></i> Save
        </button>
      </div>
    </div>

    <!-- Loading Overlay -->
    <div v-if="isLoading" class="loading-overlay">
      <div class="loading-spinner">
        <i class="fas fa-satellite fa-spin"></i>
        <p>Loading GEE exact boundary data...</p>
        <div class="progress-bar">
          <div class="progress" :style="{ width: loadingProgress + '%' }"></div>
        </div>
      </div>
    </div>

    <!-- Boundary Information Modal -->
    <div v-if="showBoundaryInfoModal" class="modal-overlay" @click="closeBoundaryInfo">
      <div class="modal-content" @click.stop>
        <div class="modal-header">
          <h3><i class="fas fa-draw-polygon"></i> GEE Exact Boundary Information</h3>
          <button @click="closeBoundaryInfo" class="close-btn">
            <i class="fas fa-times"></i>
          </button>
        </div>
        <div class="modal-body">
          <div class="boundary-details">
            <div class="detail-item">
              <span class="label">Source:</span>
              <span class="value">Google Earth Engine (FAO/GAUL/2015/level2)</span>
            </div>
            <div class="detail-item">
              <span class="label">District:</span>
              <span class="value">Udham Singh Nagar (UA), Uttarakhand</span>
            </div>
            <div class="detail-item">
              <span class="label">Dataset:</span>
              <span class="value">FAO GAUL Administrative Boundaries 2015</span>
            </div>
            <div class="detail-item">
              <span class="label">State:</span>
              <span class="value">Uttarakhand</span>
            </div>
            <div class="detail-item">
              <span class="label">Country:</span>
              <span class="value">India</span>
            </div>
            <div class="detail-item">
              <span class="label">Area:</span>
              <span class="value">{{ geeBoundary.area_sqkm }} km² ({{ (geeBoundary.area_sqkm * 100).toLocaleString() }} hectares)</span>
            </div>
            <div class="detail-item">
              <span class="label">Loading Method:</span>
              <span class="value">Direct from GEE API</span>
            </div>
          </div>
          
          <div class="coordinates-table">
            <h4>Boundary Extent</h4>
            <table>
              <thead>
                <tr>
                  <th>Direction</th>
                  <th>Latitude (N)</th>
                  <th>Longitude (E)</th>
                </tr>
              </thead>
              <tbody>
                <tr>
                  <td>Northwest</td>
                  <td>{{ geeBoundary.extent[3].toFixed(6) }}°</td>
                  <td>{{ geeBoundary.extent[0].toFixed(6) }}°</td>
                </tr>
                <tr>
                  <td>Northeast</td>
                  <td>{{ geeBoundary.extent[3].toFixed(6) }}°</td>
                  <td>{{ geeBoundary.extent[2].toFixed(6) }}°</td>
                </tr>
                <tr>
                  <td>Southeast</td>
                  <td>{{ geeBoundary.extent[1].toFixed(6) }}°</td>
                  <td>{{ geeBoundary.extent[2].toFixed(6) }}°</td>
                </tr>
                <tr>
                  <td>Southwest</td>
                  <td>{{ geeBoundary.extent[1].toFixed(6) }}°</td>
                  <td>{{ geeBoundary.extent[0].toFixed(6) }}°</td>
                </tr>
                <tr>
                  <td>Center</td>
                  <td>{{ geeBoundary.center[1].toFixed(6) }}°</td>
                  <td>{{ geeBoundary.center[0].toFixed(6) }}°</td>
                </tr>
              </tbody>
            </table>
          </div>

          <div class="boundary-properties">
            <h4>Boundary Properties</h4>
            <div class="properties-grid">
              <div class="property-item">
                <span class="property-label">ADM0_NAME:</span>
                <span class="property-value">{{ geeBoundary.properties?.adm0_name || 'India' }}</span>
              </div>
              <div class="property-item">
                <span class="property-label">ADM1_NAME:</span>
                <span class="property-value">{{ geeBoundary.properties?.adm1_name || 'Uttarakhand' }}</span>
              </div>
              <div class="property-item">
                <span class="property-label">ADM2_NAME:</span>
                <span class="property-value">{{ geeBoundary.properties?.adm2_name || 'Udham Singh Nagar' }}</span>
              </div>
              <div class="property-item">
                <span class="property-label">Shape Area:</span>
                <span class="property-value">{{ geeBoundary.properties?.shape_area ? geeBoundary.properties.shape_area.toLocaleString() : '3,055 km²' }}</span>
              </div>
            </div>
          </div>
        </div>
        <div class="modal-footer">
          <button @click="closeBoundaryInfo" class="btn">Close</button>
          <button @click="refreshBoundaryData" class="btn" :class="{ 'loading': isRefreshingBoundary }">
            <i class="fas fa-sync-alt" :class="{ 'fa-spin': isRefreshingBoundary }"></i> Refresh from GEE
          </button>
          <button @click="copyBoundaryCoords" class="btn primary">
            <i class="fas fa-copy"></i> Copy Coordinates
          </button>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import { ref, computed, watch, onMounted, onUnmounted } from 'vue';
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer } from 'ol/layer';
import { OSM, XYZ, TileWMS, Vector as VectorSource } from 'ol/source';
import GeoJSON from 'ol/format/GeoJSON';
import { Style, Stroke, Fill, Text, Circle as CircleStyle } from 'ol/style';
import { ScaleLine, defaults as defaultControls, Zoom, ZoomSlider, FullScreen } from 'ol/control';
import { fromLonLat, toLonLat } from 'ol/proj';
import { transformExtent } from 'ol/proj';
import Overlay from 'ol/Overlay';
import { getCenter } from 'ol/extent';

export default {
  name: 'MapView',
  
  props: {
    layers: {
      type: Array,
      required: true
    },
    availableDates: {
      type: Array,
      default: () => []
    },
    currentDate: {
      type: String,
      default: ''
    }
  },
  
  emits: ['date-change', 'pixel-click', 'layer-toggle'],
  
  setup(props, { emit }) {
    // Data
    const map = ref(null);
    const currentDateIndex = ref(0);
    const isPlaying = ref(false);
    const playInterval = ref(null);
    const wmsLayers = ref({});
    const popupOverlay = ref(null);
    const selectedBaseMap = ref('satellite');
    const geeBoundaryLayer = ref(null);
    const pixelInfo = ref(null);
    const isLoading = ref(false);
    const systemStatus = ref('idle');
    const lastUpdate = ref('Never');
    const loadingProgress = ref(0);
    const showGEEBoundary = ref(true);
    const boundaryColor = ref('#FF0000');
    const boundaryOpacity = ref(0.1);
    const showBoundaryInfoModal = ref(false);
    const layerStats = ref({});
    const isLayerPanelOpen = ref(true);
    const expandedLayers = ref({});
    const isRefreshingBoundary = ref(false);
    const actualBoundaryData = ref(null);
    
    // Exact GEE Boundary - Will be loaded from API
    const geeBoundary = ref({
      name: 'Udham Singh Nagar (GEE Exact)',
      coordinates: [], // Will be populated from API
      center: [79.03025, 29.41935], // Default center, will be updated
      extent: [78.9082, 29.3112, 79.1523, 29.5275], // Default extent
      area_sqkm: 3055,
      source: 'Google Earth Engine (FAO/GAUL/2015/level2)',
      properties: {
        adm0_name: 'India',
        adm1_name: 'Uttarakhand',
        adm2_name: 'Udham Singh Nagar',
        shape_area: 3055
      }
    });
    
    // Computed
    const currentDateParam = computed(() => {
      if (props.availableDates.length > 0 && currentDateIndex.value < props.availableDates.length) {
        return props.availableDates[currentDateIndex.value];
      }
      return props.currentDate || (props.availableDates.length > 0 ? props.availableDates[0] : '');
    });
    
    const formattedCurrentDate = computed(() => {
      if (currentDateParam.value) {
        const date = new Date(currentDateParam.value);
        return date.toLocaleDateString('en-IN', {
          weekday: 'short',
          year: 'numeric',
          month: 'short',
          day: 'numeric'
        });
      }
      return 'No data';
    });
    
    const tickDates = computed(() => {
      if (props.availableDates.length <= 1) return [];
      const step = Math.max(1, Math.floor(props.availableDates.length / 4));
      return [
        props.availableDates[0],
        props.availableDates[step],
        props.availableDates[step * 2],
        props.availableDates[step * 3],
        props.availableDates[props.availableDates.length - 1]
      ];
    });
    
    const systemStatusText = computed(() => {
      const statusMap = {
        'idle': 'Ready',
        'loading': 'Loading GEE data...',
        'updating': 'Updating layers...',
        'error': 'Error',
        'processing': 'Processing',
        'loading-boundary': 'Loading exact boundary...'
      };
      return statusMap[systemStatus.value] || systemStatus.value;
    });
    
    // Methods
    const initializeMap = () => {
      isLoading.value = true;
      systemStatus.value = 'loading';
      loadingProgress.value = 10;
      
      // Create empty vector source for boundary (will be populated from API)
      const geeBoundarySource = new VectorSource();
      
      geeBoundaryLayer.value = new VectorLayer({
        source: geeBoundarySource,
        style: createBoundaryStyle(),
        zIndex: 1000,
        visible: showGEEBoundary.value
      });
      
      loadingProgress.value = 30;
      
      // Create base maps
      const baseMaps = {
        'satellite': new TileLayer({
          source: new XYZ({
            url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',
            attributions: 'Tiles © Esri',
            maxZoom: 20
          }),
          visible: true,
          preload: Infinity
        }),
        'osm': new TileLayer({
          source: new OSM({
            attributions: '© OpenStreetMap contributors'
          }),
          visible: false
        }),
        'topographic': new TileLayer({
          source: new XYZ({
            url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Topo_Map/MapServer/tile/{z}/{y}/{x}',
            attributions: 'Tiles © Esri'
          }),
          visible: false
        }),
        'terrain': new TileLayer({
          source: new XYZ({
            url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Physical_Map/MapServer/tile/{z}/{y}/{x}',
            attributions: 'Tiles © Esri'
          }),
          visible: false
        })
      };
      
      loadingProgress.value = 60;
      
      // Create map view (will be adjusted after boundary load)
      const mapView = new View({
        projection: 'EPSG:3857',
        center: fromLonLat([79.03025, 29.41935]), // Default center
        zoom: 10,
        minZoom: 8,
        maxZoom: 18
      });
      
      // Create map
      map.value = new Map({
        target: 'map',
        layers: [
          baseMaps.satellite,
          baseMaps.osm,
          baseMaps.topographic,
          baseMaps.terrain,
          geeBoundaryLayer.value
        ],
        view: mapView,
        controls: defaultControls().extend([
          new Zoom(),
          new ZoomSlider(),
          new FullScreen(),
          new ScaleLine({
            units: 'metric',
            bar: true,
            steps: 4,
            text: true,
            minWidth: 100
          })
        ])
      });
      
      loadingProgress.value = 80;
      
      // Initialize popup
      initializePopup();
      
      // Add click handler
      map.value.on('singleclick', handleMapClick);
      
      // Add pointermove for hover effects
      map.value.on('pointermove', handlePointerMove);
      
      // Load exact boundary from API
      loadExactBoundary();
      
      // Initialize layers
      props.layers.forEach(layer => {
        if (layer.visible) {
          toggleLayer(layer);
        }
      });
    };
    
    const createBoundaryStyle = () => {
      const rgb = hexToRgb(boundaryColor.value);
      return new Style({
        stroke: new Stroke({
          color: boundaryColor.value,
          width: 3,
          lineDash: [5, 5]
        }),
        fill: new Fill({
          color: `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${boundaryOpacity.value})`
        })
      });
    };
    
    const loadExactBoundary = async () => {
      try {
        systemStatus.value = 'loading-boundary';
        loadingProgress.value = 40;
        
        // Fetch exact boundary from API
        const response = await fetch('http://localhost:8000/api/boundary');
        if (!response.ok) {
          throw new Error(`HTTP ${response.status}: ${response.statusText}`);
        }
        
        const boundaryData = await response.json();
        actualBoundaryData.value = boundaryData;
        
        // Update local boundary data
        geeBoundary.value = {
          name: boundaryData.name || 'Udham Singh Nagar (GEE Exact)',
          coordinates: boundaryData.geojson?.geometry?.coordinates || boundaryData.coordinates || [],
          center: boundaryData.center || [79.03025, 29.41935],
          extent: boundaryData.extent || [78.9082, 29.3112, 79.1523, 29.5275],
          area_sqkm: boundaryData.area_sqkm || 3055,
          source: boundaryData.source || 'Google Earth Engine (FAO/GAUL/2015/level2)',
          properties: boundaryData.properties || {}
        };
        
        // Clear existing features
        const source = geeBoundaryLayer.value.getSource();
        source.clear();
        
        // Add the actual polygon feature
        if (boundaryData.geojson) {
          const features = new GeoJSON().readFeatures(boundaryData.geojson, {
            dataProjection: 'EPSG:4326',
            featureProjection: 'EPSG:3857'
          });
          
          source.addFeatures(features);
          
          // Fit view to actual boundary
          const extent = source.getExtent();
          if (extent && extent[0] !== Infinity) {
            map.value.getView().fit(extent, {
              padding: [50, 50, 50, 50],
              duration: 1000
            });
          }
        }
        
        // Add district label
        addDistrictLabel();
        
        loadingProgress.value = 90;
        
      } catch (error) {
        console.error('Failed to load exact boundary:', error);
        addDistrictLabel();
      } finally {
        loadingProgress.value = 100;
        setTimeout(() => {
          isLoading.value = false;
          systemStatus.value = 'idle';
          lastUpdate.value = new Date().toLocaleTimeString();
          loadingProgress.value = 0;
        }, 500);
      }
    };
    
    const addDistrictLabel = () => {
      const source = geeBoundaryLayer.value.getSource();
      const features = source.getFeatures();
      
      if (features.length === 0) return;
      
      // Get center of first feature for label
      const geometry = features[0].getGeometry();
      const center = geometry.getInteriorPoint().getCoordinates();
      
      // Convert back to lat/lon for display
      const [lon, lat] = toLonLat(center);
      
      const labelFeature = {
        type: 'Feature',
        geometry: {
          type: 'Point',
          coordinates: [lon, lat]
        },
        properties: {
          name: geeBoundary.value.name,
          type: 'district_label'
        }
      };
      
      const labelLayer = new VectorLayer({
        source: new VectorSource({
          features: new GeoJSON().readFeatures(labelFeature, {
            dataProjection: 'EPSG:4326',
            featureProjection: 'EPSG:3857'
          })
        }),
        style: new Style({
          image: new CircleStyle({
            radius: 0, // Invisible point
            fill: new Fill({ color: 'transparent' })
          }),
          text: new Text({
            text: `${geeBoundary.value.properties?.adm2_name || 'UDHAM SINGH NAGAR'}\n(GEE Exact Boundary)`,
            font: 'bold 14px Arial',
            fill: new Fill({ color: '#FFFFFF' }),
            stroke: new Stroke({ color: '#000000', width: 3 }),
            offsetY: -40,
            textAlign: 'center',
            textBaseline: 'bottom',
            padding: [5, 5, 5, 5],
            backgroundFill: new Fill({
              color: 'rgba(0, 0, 0, 0.5)'
            }),
            backgroundStroke: new Stroke({
              color: '#FF0000',
              width: 2
            })
          })
        }),
        zIndex: 1001
      });
      
      map.value.addLayer(labelLayer);
    };
    
    const initializePopup = () => {
      const popupElement = document.getElementById('popup');
      popupOverlay.value = new Overlay({
        element: popupElement,
        autoPan: true,
        autoPanAnimation: {
          duration: 250
        },
        autoPanMargin: 50
      });
      
      map.value.addOverlay(popupOverlay.value);
    };
    
    const checkWithinExactBoundary = (lon, lat) => {
      if (!geeBoundaryLayer.value) return false;
      
      const source = geeBoundaryLayer.value.getSource();
      const features = source.getFeatures();
      
      if (features.length === 0) return false;
      
      // Transform coordinates to map projection
      const coordinate = fromLonLat([lon, lat]);
      
      // Check if coordinate is within any boundary feature
      for (const feature of features) {
        const geometry = feature.getGeometry();
        if (geometry && geometry.intersectsCoordinate(coordinate)) {
          return true;
        }
      }
      
      return false;
    };
    
    const handleMapClick = async (evt) => {
      const coordinate = evt.coordinate;
      const [lon, lat] = toLonLat(coordinate);
      
      // Check if click is within EXACT GEE boundary
      const isWithinBoundary = checkWithinExactBoundary(lon, lat);
      
      if (!isWithinBoundary) {
        showPopup(coordinate, {
          values: { error: 'Outside GEE exact boundary' },
          date: currentDateParam.value,
          location: { lat, lon },
          within_boundary: false,
          boundary_name: geeBoundary.value.name
        });
        return;
      }
      
      // Get pixel values
      try {
        systemStatus.value = 'loading';
        
        // Simulate API call
        await new Promise(resolve => setTimeout(resolve, 500));
        
        // Generate mock data for demo
        const mockData = {
          values: {
            savi: 0.6 + Math.random() * 0.2,
            kc: 0.7 + Math.random() * 0.2,
            cwr: 80 + Math.random() * 20,
            iwr: 70 + Math.random() * 20
          },
          date: currentDateParam.value,
          location: { lat, lon },
          within_boundary: true,
          boundary_name: geeBoundary.value.name,
          district: geeBoundary.value.properties?.adm2_name || 'Udham Singh Nagar'
        };
        
        pixelInfo.value = mockData;
        
        emit('pixel-click', mockData);
        showPopup(coordinate, mockData);
      } catch (error) {
        console.error('Error fetching pixel data:', error);
        showPopup(coordinate, {
          values: { error: 'Data not available' },
          date: currentDateParam.value,
          location: { lat, lon },
          within_boundary: true,
          boundary_name: geeBoundary.value.name
        });
      } finally {
        systemStatus.value = 'idle';
      }
    };
    
    const handlePointerMove = (evt) => {
      if (!showGEEBoundary.value) return;
      
      const coordinate = evt.coordinate;
      const [lon, lat] = toLonLat(coordinate);
      const isWithinBoundary = checkWithinExactBoundary(lon, lat);
      
      // Update cursor style
      const mapElement = document.getElementById('map');
      if (mapElement) {
        mapElement.style.cursor = isWithinBoundary ? 'crosshair' : 'not-allowed';
      }
    };
    
    const showPopup = (coordinate, data) => {
      const content = document.getElementById('popup-content');
      const [lon, lat] = toLonLat(coordinate);
      const isWithinBoundary = data.within_boundary;
      
      let html = '<div class="popup-content">';
      html += `<div class="popup-header">${formattedCurrentDate.value}</div>`;
      html += `<div class="popup-location">${lat.toFixed(4)}° N, ${lon.toFixed(4)}° E</div>`;
      html += `<div class="popup-boundary">${geeBoundary.value.name}</div>`;
      html += `<div class="boundary-status ${isWithinBoundary ? 'within' : 'outside'}">`;
      html += `<i class="fas ${isWithinBoundary ? 'fa-check-circle' : 'fa-times-circle'}"></i>`;
      html += `${isWithinBoundary ? 'Within GEE exact boundary' : 'Outside GEE exact boundary'}`;
      html += '</div>';
      
      if (data.values && !data.values.error) {
        for (const [param, value] of Object.entries(data.values)) {
          if (value !== null && value !== undefined) {
            html += `
              <div class="popup-parameter">
                <span class="param-name">${getParameterName(param)}:</span>
                <span class="param-value">${typeof value === 'number' ? value.toFixed(3) : value} ${getParameterUnit(param)}</span>
              </div>
            `;
          }
        }
      } else if (data.values?.error) {
        html += `<div class="popup-error">${data.values.error}</div>`;
      }
      
      html += '</div>';
      content.innerHTML = html;
      
      popupOverlay.value.setPosition(coordinate);
    };
    
    const getParameterName = (param) => {
      const names = {
        'savi': 'Soil Adjusted Vegetation Index',
        'kc': 'Crop Coefficient',
        'cwr': 'Crop Water Requirement',
        'iwr': 'Irrigation Water Requirement',
        'ndvi': 'NDVI',
        'error': 'Error'
      };
      return names[param] || param.toUpperCase();
    };
    
    const getParameterUnit = (param) => {
      const units = {
        'savi': 'index',
        'kc': 'ratio',
        'cwr': 'mm/day',
        'iwr': 'mm/day',
        'ndvi': 'index',
        'error': ''
      };
      return units[param] || '';
    };
    
    const getLayerIcon = (layerId) => {
      const icons = {
        'savi': 'fas fa-leaf',
        'kc': 'fas fa-seedling',
        'cwr': 'fas fa-tint',
        'iwr': 'fas fa-water',
        'ndvi': 'fas fa-mountain'
      };
      return icons[layerId] || 'fas fa-layer-group';
    };
    
    const toggleLayer = (layer) => {
      if (!wmsLayers.value[layer.id]) {
        // Add new layer
        const geoserverUrl = 'http://localhost:9090/geoserver/irrigation/wms';
        
        wmsLayers.value[layer.id] = new TileLayer({
          source: new TileWMS({
            url: geoserverUrl,
            params: {
              'LAYERS': `irrigation:${getLayerName(layer.id)}`,
              'TILED': true,
              'FORMAT': 'image/png',
              'TRANSPARENT': true,
              'TIME': currentDateParam.value
            },
            serverType: 'geoserver',
            transition: 0,
            crossOrigin: 'anonymous'
          }),
          visible: layer.visible,
          opacity: layer.opacity || 0.8,
          zIndex: 500
        });
        
        map.value.addLayer(wmsLayers.value[layer.id]);
        
        // Fetch layer stats
        fetchLayerStats(layer.id);
      } else {
        // Toggle visibility
        wmsLayers.value[layer.id].setVisible(layer.visible);
        wmsLayers.value[layer.id].setOpacity(layer.opacity || 0.8);
      }
      
      emit('layer-toggle', layer);
    };
    
    const toggleLayerOptions = (layerId) => {
      expandedLayers.value[layerId] = !expandedLayers.value[layerId];
    };
    
    const updateLayerOpacity = (layer) => {
      if (wmsLayers.value[layer.id]) {
        wmsLayers.value[layer.id].setOpacity(layer.opacity || 0.8);
      }
    };
    
    const fetchLayerStats = async (layerId) => {
      try {
        // Simulated API call
        await new Promise(resolve => setTimeout(resolve, 300));
        
        // Mock data for demo
        layerStats.value[layerId] = {
          min: Math.random() * 5,
          max: Math.random() * 20,
          mean: Math.random() * 10 + 5,
          std: Math.random() * 2
        };
      } catch (error) {
        console.error(`Error fetching stats for ${layerId}:`, error);
      }
    };
    
    const changeBaseMap = () => {
      const baseLayers = map.value.getLayers().getArray();
      baseLayers.forEach((layer, index) => {
        if (index < 4) { // First 4 layers are base maps
          layer.setVisible(false);
        }
      });
      
      // Show selected base map
      const baseMapIndex = {
        'satellite': 0,
        'osm': 1,
        'topographic': 2,
        'terrain': 3
      }[selectedBaseMap.value];
      
      if (baseMapIndex !== undefined) {
        baseLayers[baseMapIndex].setVisible(true);
      }
    };
    
    const toggleGEEBoundary = () => {
      if (geeBoundaryLayer.value) {
        geeBoundaryLayer.value.setVisible(showGEEBoundary.value);
      }
    };
    
    const updateBoundaryStyle = () => {
      if (geeBoundaryLayer.value) {
        geeBoundaryLayer.value.setStyle(createBoundaryStyle());
      }
    };
    
    const hexToRgb = (hex) => {
      const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
      return result ? {
        r: parseInt(result[1], 16),
        g: parseInt(result[2], 16),
        b: parseInt(result[3], 16)
      } : { r: 255, g: 0, b: 0 };
    };
    
    const togglePlay = () => {
      if (isPlaying.value) {
        stopPlayback();
      } else {
        startPlayback();
      }
    };
    
    const startPlayback = () => {
      if (props.availableDates.length <= 1) return;
      
      isPlaying.value = true;
      playInterval.value = setInterval(() => {
        currentDateIndex.value = (currentDateIndex.value + 1) % props.availableDates.length;
        updateMapDate();
        
        // Update progress
        loadingProgress.value = ((currentDateIndex.value + 1) / props.availableDates.length) * 100;
      }, 1500); // 1.5 seconds per frame
    };
    
    const stopPlayback = () => {
      isPlaying.value = false;
      if (playInterval.value) {
        clearInterval(playInterval.value);
        playInterval.value = null;
      }
      loadingProgress.value = 0;
    };
    
    const clearPixelInfo = () => {
      pixelInfo.value = null;
      if (popupOverlay.value) {
        popupOverlay.value.setPosition(undefined);
      }
    };
    
    const closePopup = () => {
      if (popupOverlay.value) {
        popupOverlay.value.setPosition(undefined);
      }
    };
    
    const formatTickDate = (dateStr) => {
      const date = new Date(dateStr);
      return date.toLocaleDateString('en-IN', { month: 'short', day: 'numeric' });
    };
    
    const zoomIn = () => {
      const view = map.value.getView();
      view.animate({
        zoom: view.getZoom() + 1,
        duration: 250
      });
    };
    
    const zoomOut = () => {
      const view = map.value.getView();
      view.animate({
        zoom: view.getZoom() - 1,
        duration: 250
      });
    };
    
    const resetView = () => {
      if (geeBoundaryLayer.value) {
        const source = geeBoundaryLayer.value.getSource();
        const extent = source.getExtent();
        
        if (extent && extent[0] !== Infinity) {
          map.value.getView().fit(extent, {
            padding: [50, 50, 50, 50],
            duration: 1000
          });
        }
      }
    };
    
    const toggleFullscreen = () => {
      const mapContainer = document.querySelector('.map-container');
      if (!document.fullscreenElement) {
        if (mapContainer.requestFullscreen) {
          mapContainer.requestFullscreen().catch(err => {
            console.error(`Error attempting to enable fullscreen: ${err.message}`);
          });
        }
      } else {
        if (document.exitFullscreen) {
          document.exitFullscreen();
        }
      }
    };
    
    const downloadPixelData = () => {
      if (!pixelInfo.value) return;
      
      const dataStr = JSON.stringify(pixelInfo.value, null, 2);
      const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);
      
      const exportFileDefaultName = `pixel_data_${pixelInfo.value.location.lat}_${pixelInfo.value.location.lon}_${pixelInfo.value.date}.json`;
      
      const linkElement = document.createElement('a');
      linkElement.setAttribute('href', dataUri);
      linkElement.setAttribute('download', exportFileDefaultName);
      linkElement.click();
    };
    
    const addToFavorites = () => {
      if (!pixelInfo.value) return;
      
      const favorites = JSON.parse(localStorage.getItem('mapFavorites') || '[]');
      favorites.push({
        ...pixelInfo.value,
        savedAt: new Date().toISOString()
      });
      localStorage.setItem('mapFavorites', JSON.stringify(favorites));
      
      alert('Location saved to favorites!');
    };
    
    const showBoundaryInfo = () => {
      showBoundaryInfoModal.value = true;
    };
    
    const closeBoundaryInfo = () => {
      showBoundaryInfoModal.value = false;
    };
    
    const refreshBoundaryData = async () => {
      try {
        isRefreshingBoundary.value = true;
        
        // Reload boundary data
        await loadExactBoundary();
        
        // Update modal with fresh data
        if (showBoundaryInfoModal.value) {
          showBoundaryInfoModal.value = false;
          setTimeout(() => {
            showBoundaryInfoModal.value = true;
          }, 100);
        }
        
        alert('Boundary data refreshed from GEE!');
      } catch (error) {
        console.error('Failed to refresh boundary:', error);
        alert('Failed to refresh boundary data');
      } finally {
        isRefreshingBoundary.value = false;
      }
    };
    
    const copyBoundaryCoords = () => {
      const coords = JSON.stringify(geeBoundary.value, null, 2);
      navigator.clipboard.writeText(coords)
        .then(() => alert('Boundary data copied to clipboard!'))
        .catch(err => console.error('Failed to copy:', err));
    };
    
    const toggleLayerPanel = () => {
      isLayerPanelOpen.value = !isLayerPanelOpen.value;
    };
    
    const updateMapDate = () => {
      if (!currentDateParam.value) return;
      
      systemStatus.value = 'updating';
      
      Object.keys(wmsLayers.value).forEach(param => {
        const layer = wmsLayers.value[param];
        if (layer) {
          const source = layer.getSource();
          source.updateParams({
            'TIME': currentDateParam.value
          });
        }
      });
      
      emit('date-change', currentDateParam.value);
      
      setTimeout(() => {
        systemStatus.value = 'idle';
      }, 500);
    };
    
    // Lifecycle
    onMounted(() => {
      initializeMap();
      
      // Set initial date index
      if (props.currentDate && props.availableDates.length > 0) {
        const index = props.availableDates.indexOf(props.currentDate);
        if (index !== -1) {
          currentDateIndex.value = index;
        }
      }
    });
    
    onUnmounted(() => {
      if (playInterval.value) {
        clearInterval(playInterval.value);
      }
    });
    
    // Watchers
    watch(currentDateIndex, updateMapDate);
    
    watch(() => props.currentDate, (newDate) => {
      if (newDate && props.availableDates.length > 0) {
        const index = props.availableDates.indexOf(newDate);
        if (index !== -1) {
          currentDateIndex.value = index;
        }
      }
    });
    
    return {
      // Data
      currentDateIndex,
      isPlaying,
      selectedBaseMap,
      pixelInfo,
      isLoading,
      systemStatus,
      lastUpdate,
      loadingProgress,
      showGEEBoundary,
      boundaryColor,
      boundaryOpacity,
      showBoundaryInfoModal,
      layerStats,
      isLayerPanelOpen,
      expandedLayers,
      isRefreshingBoundary,
      geeBoundary,
      
      // Computed
      formattedCurrentDate,
      currentDateParam,
      tickDates,
      systemStatusText,
      
      // Methods
      togglePlay,
      toggleLayer,
      toggleLayerOptions,
      updateLayerOpacity,
      changeBaseMap,
      getParameterName,
      getParameterUnit,
      getLayerIcon,
      clearPixelInfo,
      closePopup,
      formatTickDate,
      toggleGEEBoundary,
      updateBoundaryStyle,
      zoomIn,
      zoomOut,
      resetView,
      toggleFullscreen,
      downloadPixelData,
      addToFavorites,
      showBoundaryInfo,
      closeBoundaryInfo,
      refreshBoundaryData,
      copyBoundaryCoords,
      toggleLayerPanel
    };
  }
};

// Helper functions
function getLayerName(param) {
  const layerNames = {
    'savi': 'SAVI_wheat_10m',
    'kc': 'Predicted_Kc_10m',
    'cwr': 'Predicted_CWR_10m',
    'iwr': 'Predicted_IWR_10m',
    'ndvi': 'NDVI'
  };
  return layerNames[param] || param;
}
</script>

